/** Display name for a code (or the code itself if unknown), for UI + summaries. */
const NAME_BY_CODE: ReadonlyMap<string, string> = new Map(COUNTRIES.map((c) => [c.code, c.name]));
export function countryName(code: string): string {
  return NAME_BY_CODE.get(code.toUpperCase()) ?? code;
}

/** Every valid country code as a runtime tuple — the source for the zod enum below. */
export const COUNTRY_CODES = COUNTRIES.map((c) => c.code) as [string, ...string[]];

const COUNTRY_CODE_SET: ReadonlySet<string> = new Set(COUNTRY_CODES);

/** True iff `s` is an allowlisted ISO alpha-2 country code (case-insensitive). Never throws. */
export function isCountryCode(s: unknown): s is string {
  return typeof s === "string" && COUNTRY_CODE_SET.has(s.toUpperCase());
}

/**
 * Normalize a viewer/CDN country string to a canonical allowlisted code, or null. CloudFront emits an
 * uppercase alpha-2 (and `XX`/`ZZ`/`O1` for unknown/anonymizing networks); anything not on the
 * allowlist → null ("unknown"), which the serving path treats as fail-closed for geo-targeted ads.
 */
export function normalizeCountry(input: string | null | undefined): string | null {
  if (!input) return null;
  const code = input.trim().toUpperCase();
  return COUNTRY_CODE_SET.has(code) ? code : null;
}

/** Zod enum over the closed country allowlist (uppercase codes). */
export const CountryCodeSchema = z.enum(COUNTRY_CODES);
